from flask import Flask, request
import face_recognition
import os
import pickle
app = Flask(__name__)

# Load the trained model
with open('trained_model.pkl', 'rb') as f:
    known_face_encodings = pickle.load(f)
known_face_names = list(known_face_encodings.keys())

@app.route('/recognize', methods=['POST'])
def recognize():
    if not request.files or 'image' not in request.files:
        return {"error": "No image file provided"}, 400
    
    # Load the uploaded image file
    image_file = request.files['image']
    image = face_recognition.load_image_file(image_file)
    
    # Find all facial features in all the faces in the image
    face_locations = face_recognition.face_locations(image)
    face_encodings = face_recognition.face_encodings(image, face_locations)
    
    result = []
    for face_encoding in face_encodings:
        # See if the face is a match for the known faces
        matches = face_recognition.compare_faces(known_face_encodings.values(), face_encoding)
        
        name = "Unknown"
        confidence = 0
        # If a match was found in known_face_encodings, just use the first one.
        if True in matches:
            first_match_index = matches.index(True)
            name = list(known_face_encodings.keys())[first_match_index]
            confidence = 1 - face_recognition.face_distance([known_face_encodings[name]], face_encoding)[0]
        
        result.append({"name": name, "confidence": confidence})
    
    return {"results": result}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)